+const transactionalReloadStateFile = "reload-status.json"
+
+type transactionalReloader struct {
+	filename              string
+	enableExemplarStorage bool
+	logger                *slog.Logger
+	noStepSubqueryInterval *safePromQLNoStepSubqueryInterval
+	storagePath           string
+
+	mu       sync.RWMutex
+	lastGood *config.Config
+	status   api_v1.ReloadStatus
+}
+
+func newTransactionalReloader(filename string, enableExemplarStorage bool, storagePath string, logger *slog.Logger, noStepSubqueryInterval *safePromQLNoStepSubqueryInterval) *transactionalReloader {
+	r := &transactionalReloader{
+		filename: filename, enableExemplarStorage: enableExemplarStorage, storagePath: storagePath,
+		logger: logger, noStepSubqueryInterval: noStepSubqueryInterval,
+		status: emptyReloadStatus(),
+	}
+	b, err := os.ReadFile(filepath.Join(storagePath, transactionalReloadStateFile))
+	if err == nil {
+		var status api_v1.ReloadStatus
+		if json.Unmarshal(b, &status) == nil && validReloadStatus(status) {
+			r.status = normalizeReloadStatus(status)
+		} else {
+			logger.Warn("Ignoring invalid persisted transactional reload status", "file", filepath.Join(storagePath, transactionalReloadStateFile))
+		}
+	}
+	return r
+}
+
+func emptyReloadStatus() api_v1.ReloadStatus {
+	return api_v1.ReloadStatus{AppliedReloaders: []string{}, ReloaderTimingsMS: map[string]int64{}, ErrorCategory: "none"}
+}
+
+func validReloadStatus(s api_v1.ReloadStatus) bool {
+	return s.ErrorCategory == "none" || s.ErrorCategory == "load_error" || s.ErrorCategory == "apply_error" || s.ErrorCategory == "rollback_error"
+}
+
+func normalizeReloadStatus(s api_v1.ReloadStatus) api_v1.ReloadStatus {
+	if s.AppliedReloaders == nil {
+		s.AppliedReloaders = []string{}
+	}
+	if s.ReloaderTimingsMS == nil {
+		s.ReloaderTimingsMS = map[string]int64{}
+	}
+	return s
+}
+
+func (r *transactionalReloader) Status() api_v1.ReloadStatus {
+	r.mu.RLock()
+	defer r.mu.RUnlock()
+	s := normalizeReloadStatus(r.status)
+	s.AppliedReloaders = append([]string(nil), s.AppliedReloaders...)
+	s.ReloaderTimingsMS = make(map[string]int64, len(r.status.ReloaderTimingsMS))
+	for name, timing := range r.status.ReloaderTimingsMS {
+		s.ReloaderTimingsMS[name] = timing
+	}
+	return s
+}
+
+func (r *transactionalReloader) saveStatus(status api_v1.ReloadStatus) {
+	r.mu.Lock()
+	r.status = normalizeReloadStatus(status)
+	b, err := json.Marshal(r.status)
+	if err == nil {
+		tmp := filepath.Join(r.storagePath, transactionalReloadStateFile+".tmp")
+		err = os.WriteFile(tmp, b, 0o644)
+		if err == nil {
+			err = os.Rename(tmp, filepath.Join(r.storagePath, transactionalReloadStateFile))
+		}
+	}
+	r.mu.Unlock()
+	if err != nil {
+		r.logger.Error("Unable to persist transactional reload status", "err", err)
+	}
+}
+
+// Reload applies a configuration in order. Startup calls it with record=false so
+// the initial successful configuration becomes the rollback target without
+// creating an operator-visible reload attempt.
+func (r *transactionalReloader) Reload(record bool, callback func(bool), rls ...reloader) error {
+	conf, err := config.LoadFile(r.filename, agentMode, r.logger)
+	if err != nil {
+		err = fmt.Errorf("couldn't load configuration (--config.file=%q): %w", r.filename, err)
+		if record {
+			r.saveStatus(api_v1.ReloadStatus{LastReloadID: time.Now().UTC().Format(time.RFC3339Nano), ErrorCategory: "load_error", ErrorMessage: err.Error(), AppliedReloaders: []string{}, ReloaderTimingsMS: map[string]int64{}})
+		}
+		callback(false)
+		return err
+	}
+	if r.enableExemplarStorage && conf.StorageConfig.ExemplarsConfig == nil {
+		conf.StorageConfig.ExemplarsConfig = &config.DefaultExemplarsConfig
+	}
+
+	status := emptyReloadStatus()
+	status.LastReloadID = time.Now().UTC().Format(time.RFC3339Nano)
+	applied := make([]int, 0, len(rls))
+	for i, rl := range rls {
+		start := time.Now()
+		err := rl.reloader(conf)
+		status.ReloaderTimingsMS[rl.name] = durationToInt64Millis(time.Since(start))
+		if err != nil {
+			status.ErrorCategory = "apply_error"
+			status.ErrorMessage = err.Error()
+			status.FailedReloader = rl.name
+			status.AppliedReloaders = append(status.AppliedReloaders, reloaderNames(rls, applied)...)
+			if len(applied) > 0 && r.rollback(rls, applied) {
+				status.RollbackAttempted = true
+				status.RollbackSuccessful = true
+			} else if len(applied) > 0 {
+				status.RollbackAttempted = true
+				status.ErrorCategory = "rollback_error"
+				status.ErrorMessage = fmt.Sprintf("applying %s failed: %v; rollback failed", rl.name, err)
+			}
+			if record {
+				r.saveStatus(status)
+			}
+			callback(false)
+			return fmt.Errorf("error applying configuration with reloader %q: %w", rl.name, err)
+		}
+		applied = append(applied, i)
+	}
+
+	r.mu.Lock()
+	r.lastGood = conf
+	r.mu.Unlock()
+	updateGoGC(conf, r.logger)
+	r.noStepSubqueryInterval.Set(conf.GlobalConfig.EvaluationInterval)
+	if record {
+		status.LastReloadSuccessful = true
+		r.saveStatus(status)
+	}
+	callback(true)
+	return nil
+}
+
+func (r *transactionalReloader) rollback(rls []reloader, applied []int) bool {
+	r.mu.RLock()
+	lastGood := r.lastGood
+	r.mu.RUnlock()
+	if lastGood == nil {
+		return false
+	}
+	for i := len(applied) - 1; i >= 0; i-- {
+		if err := rls[applied[i]].reloader(lastGood); err != nil {
+			r.logger.Error("Failed to roll back configuration", "reloader", rls[applied[i]].name, "err", err)
+			return false
+		}
+	}
+	return true
+}
+
+func reloaderNames(rls []reloader, indexes []int) []string {
+	names := make([]string, 0, len(indexes))
+	for _, i := range indexes {
+		names = append(names, rls[i].name)
+	}
+	return names
+}
